using Microsoft.AspNetCore.Identity;

namespace sv_c3f3d7078c704bc2a5360f6280c902d7.Data;

public class ApplicationUser : IdentityUser
{
}

using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace sv_c3f3d7078c704bc2a5360f6280c902d7.Data;

public class ApplicationDbContext : IdentityDbContext<ApplicationUser>
{
    public ApplicationDbContext(DbContextOptions<ApplicationDbContext> options)
        : base(options)
    {
    }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Server;
using Microsoft.AspNetCore.Identity;
using Microsoft.Extensions.Options;
using sv_c3f3d7078c704bc2a5360f6280c902d7.Data;

namespace sv_c3f3d7078c704bc2a5360f6280c902d7;

// Periodically revalidates the authentication state against the Identity store,
// ensuring that revoked sessions (e.g. password change) are detected.
public class IdentityRevalidatingAuthenticationStateProvider
    : RevalidatingServerAuthenticationStateProvider
{
    private readonly IServiceScopeFactory _scopeFactory;
    private readonly IOptions<IdentityOptions> _options;

    public IdentityRevalidatingAuthenticationStateProvider(
        ILoggerFactory loggerFactory,
        IServiceScopeFactory scopeFactory,
        IOptions<IdentityOptions> options)
        : base(loggerFactory)
    {
        _scopeFactory = scopeFactory;
        _options = options;
    }

    protected override TimeSpan RevalidationInterval => TimeSpan.FromMinutes(30);

    protected override async Task<bool> ValidateAuthenticationStateAsync(
        AuthenticationState authenticationState, CancellationToken cancellationToken)
    {
        await using var scope = _scopeFactory.CreateAsyncScope();
        var userManager = scope.ServiceProvider
            .GetRequiredService<UserManager<ApplicationUser>>();
        return await ValidateSecurityStampAsync(userManager, authenticationState.User);
    }

    private async Task<bool> ValidateSecurityStampAsync(
        UserManager<ApplicationUser> userManager, ClaimsPrincipal principal)
    {
        var user = await userManager.GetUserAsync(principal);
        if (user is null)
            return false;
        if (!userManager.SupportsUserSecurityStamp)
            return true;
        var principalStamp = principal.FindFirstValue(
            _options.Value.ClaimsIdentity.SecurityStampClaimType);
        var userStamp = await userManager.GetSecurityStampAsync(user);
        return principalStamp == userStamp;
    }
}

@page "/account/login"
@using Microsoft.AspNetCore.Identity
@using sv_c3f3d7078c704bc2a5360f6280c902d7.Data
@using System.ComponentModel.DataAnnotations
@attribute [Microsoft.AspNetCore.Components.Endpoints.ExcludeFromInteractiveRouting]

@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Login</PageTitle>

<div class="row justify-content-center">
    <div class="col-md-4">
        <h1>Login</h1>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <EditForm Model="Input" FormName="login" OnValidSubmit="LoginUser" method="post">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <InputText id="email" @bind-Value="Input.Email" class="form-control" autocomplete="username" />
                <ValidationMessage For="() => Input.Email" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <InputText id="password" @bind-Value="Input.Password" type="password" class="form-control" autocomplete="current-password" />
                <ValidationMessage For="() => Input.Password" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-primary w-100">Log in</button>
        </EditForm>

        <div class="mt-3 text-center">
            <p>Don't have an account? <a href="account/register">Register</a></p>
        </div>
    </div>
</div>

@code {
    private string? errorMessage;

    [CascadingParameter]
    public HttpContext HttpContext { get; set; } = default!;

    [SupplyParameterFromForm]
    private LoginInput Input { get; set; } = new();

    private async Task LoginUser()
    {
        var result = await SignInManager.PasswordSignInAsync(
            Input.Email!, Input.Password!, isPersistent: false, lockoutOnFailure: false);

        if (result.Succeeded)
        {
            Navigation.NavigateTo("/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }

    private sealed class LoginInput
    {
        [Required]
        [EmailAddress]
        public string? Email { get; set; }

        [Required]
        [DataType(DataType.Password)]
        public string? Password { get; set; }
    }
}

@page "/account/register"
@using Microsoft.AspNetCore.Identity
@using sv_c3f3d7078c704bc2a5360f6280c902d7.Data
@using System.ComponentModel.DataAnnotations
@attribute [Microsoft.AspNetCore.Components.Endpoints.ExcludeFromInteractiveRouting]

@inject UserManager<ApplicationUser> UserManager
@inject NavigationManager Navigation

<PageTitle>Register</PageTitle>

<div class="row justify-content-center">
    <div class="col-md-4">
        <h1>Register</h1>

        @if (errorMessages.Count > 0)
        {
            <div class="alert alert-danger">
                <ul class="mb-0">
                    @foreach (var msg in errorMessages)
                    {
                        <li>@msg</li>
                    }
                </ul>
            </div>
        }

        <EditForm Model="Input" FormName="register" OnValidSubmit="RegisterUser" method="post">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <InputText id="email" @bind-Value="Input.Email" class="form-control" autocomplete="username" />
                <ValidationMessage For="() => Input.Email" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <InputText id="password" @bind-Value="Input.Password" type="password" class="form-control" autocomplete="new-password" />
                <ValidationMessage For="() => Input.Password" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="confirmPassword" class="form-label">Confirm Password</label>
                <InputText id="confirmPassword" @bind-Value="Input.ConfirmPassword" type="password" class="form-control" autocomplete="new-password" />
                <ValidationMessage For="() => Input.ConfirmPassword" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-primary w-100">Register</button>
        </EditForm>

        <div class="mt-3 text-center">
            <p>Already have an account? <a href="account/login">Login</a></p>
        </div>
    </div>
</div>

@code {
    private List<string> errorMessages = new();

    [CascadingParameter]
    public HttpContext HttpContext { get; set; } = default!;

    [SupplyParameterFromForm]
    private RegisterInput Input { get; set; } = new();

    private async Task RegisterUser()
    {
        var user = new ApplicationUser { UserName = Input.Email, Email = Input.Email };
        var result = await UserManager.CreateAsync(user, Input.Password!);

        if (result.Succeeded)
        {
            Navigation.NavigateTo("/account/login", forceLoad: true);
        }
        else
        {
            errorMessages = result.Errors.Select(e => e.Description).ToList();
        }
    }

    private sealed class RegisterInput
    {
        [Required]
        [EmailAddress]
        public string? Email { get; set; }

        [Required]
        [StringLength(100, MinimumLength = 6, ErrorMessage = "Password must be at least {2} characters.")]
        [DataType(DataType.Password)]
        public string? Password { get; set; }

        [Required]
        [DataType(DataType.Password)]
        [Compare("Password", ErrorMessage = "Passwords do not match.")]
        [Display(Name = "Confirm Password")]
        public string? ConfirmPassword { get; set; }
    }
}

